import{_ as t,o,c as p,j as e,a as l,a1 as r}from"./chunks/framework.Bp7r_-XI.js";const b=JSON.parse('{"title":"Z-180 Close Combat Rifle Z-180散射步枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/Z-180 Close Combat Rifle Z-180散射步枪.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/Z-180 Close Combat Rifle Z-180散射步枪.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/Z-180 Close Combat Rifle Z-180散射步枪.md"};function i(n,a,c,d,_,C){return o(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"z-180-close-combat-rifle-z-180散射步枪",tabindex:"-1"},[l("Z-180 Close Combat Rifle Z-180散射步枪 "),e("a",{class:"header-anchor",href:"#z-180-close-combat-rifle-z-180散射步枪","aria-label":'Permalink to "Z-180 Close Combat Rifle Z-180散射步枪"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),r('<h1 id="z-180-close-combat-rifle-z-180散射步枪-1" tabindex="-1">Z-180 Close Combat Rifle Z-180散射步枪 <a class="header-anchor" href="#z-180-close-combat-rifle-z-180散射步枪-1" aria-label="Permalink to &quot;Z-180 Close Combat Rifle Z-180散射步枪&quot;">​</a></h1><p>Z-180 Close Combat Rifle /Z-180散射步枪</p><p>Z-180 Close Combat Rifle /Z-180散射步枪--通常被称为Scattershot散射枪，是是一种先行者定向能武器，它实际上是一种类似于人类霰弹枪的武器，最初是在先行者-洪魔战争即将结束时作为近距离防御武器使用的。它的火力在相对较近的距离内非常危险，一枪可以发射多个单独的射弹，其最显著的特点是子弹可以在表面反弹 。</p><p>（这里如果可以插入图片就太好了，这把枪挺帅的）</p><p>价格：C+1000</p><p>本质：科技</p><p>制造商：锻匠总装工场</p><p>类型：霰弹枪</p><p>长度：115.5 厘米（45.5 英寸）</p><p>宽度：10.7 厘米（4.2 英寸）</p><p>高度：34.1 厘米（13.4 英寸）</p><p>体积：3</p><p>弹药类型：硬光弹药</p><p>供弹系统：5发弹仓</p><p>有效射程：30米</p><p>力量需求：3</p><p>武器伤害：10L</p><p>这种武器具有先行者武器设计的特点：棱角性和金属质感。从它的自动装弹充能过程和悬浮部件可以看出，它的一部分似乎被一种能量场连接在一起。当武器自动装弹充能以及装弹完成后的整枪，可以看到橙色光源；当武器发射时，这些光源会变得更亮。武器采用一个折管式弹仓容纳五个弹药单元。</p><p>来自先行者的能源科技使其可以提供的硬光弹药视之为无限，以进行5次射击（拥有5发子弹），这会以百分比的形式显示在枪械的悬浮屏幕上，每次射击会累计20%的热量，累计到达百分之百时，需要以一个迅捷动作将枪管向两侧弯折散热，待计数器归0后才可继续射击。显然的，这种武器不具有常规意义上的枪膛和撞针，仅能射击硬光弹药，这些硬光弹药将为攻击提供【能量武器】特性。</p><p>散射枪是架构者护卫队的首选武器 ，设计之初便是为了在在狭窄的环境下作战。Z-180散射步枪一次射击可以射出8枚弹丸，若在射击目标的周围大约一米范围内（不包括地面）具有不小于1平方米的坚硬表面，那么这些弹丸就会在表面上进行反弹，对目标额外造成伤害，视为该次攻击中的1点严重伤害转为韧性。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',22)])])}const m=t(s,[["render",i]]);export{b as __pageData,m as default};
